arguments.file_text:
#:property AllowUnsafeBlocks=true

Span<nint> a = stackalloc nint[5];
for (int i = 0; i < a.Length; i++)
    a[i] = (nint)(i * 10);

Console.WriteLine($"Span<nint> length: {a.Length}, element size: {sizeof(nint)} bytes");
for (int i = 0; i < a.Length; i++)
    Console.WriteLine($"  a[{i}] = {a[i]}");

Span<nuint> b = stackalloc nuint[3];
b[0] = 100; b[1] = 200; b[2] = 300;

Console.WriteLine($"\nSpan<nuint> length: {b.Length}, element size: {sizeof(nuint)} bytes");
for (int i = 0; i < b.Length; i++)
    Console.WriteLine($"  b[{i}] = {b[i]}");

